```python
cow = {'Body': {'result': True}}

def return_it(acc, item):
    return acc[item]

def reduce_it(obj, path):
    dots = path.split('.')
    main = first(dots)
    unwind_that_sucka = reduce_(dots, return_it, obj)
    return unwind_that_sucka

def get2(obj, path, default):
    try:
        return reduce_it(obj, path)
