#include <pybind11/pybind11.h>

namespace py = pybind11;

struct Test {
    Test(int v) : value{v} {}
    int m2(py::args args, py::kwargs kwargs) {
        return 100 * value + 10 * py::cast<int>(args[0]) + py::cast<int>(kwargs["foo"]);
    }
    int value;
};

PYBIND11_PLUGIN(mytest) {
    py::module m("mytest");

    py::class_<Test>(m, "Test")
        .def(py::init<int>())
        .def_readwrite("value", &Test::value)
        // Instance method via lambda function:
